{
var shape = GetChoice(parameters, "shape", "circle");
        var sizeParam = GetFloat(parameters, "size", 0.6f);
        var scaleX = GetFloat(parameters, "scaleX", 1f);
        var scaleY = GetFloat(parameters, "scaleY", 1f);
        var hardness = GetFloat(parameters, "edgeHardness", 1f);
        var fillColor = GetColor(parameters, "color", Colors.White);
        var r = fillColor.R / 255f;
        var g = fillColor.G / 255f;
        var b = fillColor.B / 255f;
        var rotation = GetFloat(parameters, "rotation", 0f) * MathF.PI / 180f;
        var offsetX = GetFloat(parameters, "offsetX", 0f);
        var offsetY = GetFloat(parameters, "offsetY", 0f);
        var strokeWidth = GetFloat(parameters, "strokeWidth", 0f);
        var strokeColor = GetColor(parameters, "strokeColor", Colors.Black);
        var strokeR = strokeColor.R / 255f;
        var strokeG = strokeColor.G / 255f;
        var strokeB = strokeColor.B / 255f;
        var dither = GetBool(parameters, "dither");
        var invert = GetBool(parameters, "invert");

        // Parse exported point list for custom shapes into sub-paths.
        List<(List<Point> sampled, bool closed, float width, Color color)>? sampledPaths = null;
        if (shape == "custom" && parameters.TryGetValue("customShape", out var ptObj) && ptObj is IReadOnlyList<Point> pts && pts.Count >= 1)
        {
            sampledPaths = new();
            var segment = new List<Point>();
            float segWidth = 1f;
            var segColor = Colors.White;
            foreach (var pt in pts)
            {
                // Editor state section marker — everything after (NaN, ≤-9000) is editor
                // metadata used by ShapeDrawingWindow; stop raster processing here.
                if (double.IsNaN(pt.X) && !double.IsNaN(pt.Y) && pt.Y <= -9000.0) break;

                // Color marker: (NegativeInfinity, packedRgb) encodes the per-stroke draw color.
                if (double.IsNegativeInfinity(pt.X))
                {
                    var packed = (long)Math.Max(0.0, pt.Y);
                    segColor = Color.FromRgb((byte)(packed & 0xFF), (byte)((packed >> 8) & 0xFF), (byte)((packed >> 16) & 0xFF));
                    continue;
                }

                // Fill polygon marker: (PositiveInfinity, packedRgb) — the preceding points form
                // a closed filled polygon. Store with sentinel width = -1 to distinguish from strokes.
                if (double.IsPositiveInfinity(pt.X))
                {
                    var packed = (long)Math.Max(0.0, pt.Y);
                    var fillCol = Color.FromRgb((byte)(packed & 0xFF), (byte)((packed >> 8) & 0xFF), (byte)((packed >> 16) & 0xFF));
                    if (segment.Count >= 3)
                        sampledPaths.Add((new List<Point>(segment), true, -1f, fillCol));
                    segment.Clear();
                    segWidth = 1f;
                    segColor = Colors.White;
                    continue;
                }

                // Separator: (NaN, NaN) or (NaN, width)
                if (double.IsNaN(pt.X) || double.IsNaN(pt.Y))
                {
                    if (double.IsNaN(pt.X) && !double.IsNaN(pt.Y)) segWidth = (float)pt.Y;
                    if (segment.Count > 0)
                    {
                        // Only treat a path as "closed" if its first and last points actually match
                        // (this avoids implicitly connecting freehand strokes when the drawing
                        // surface didn't intend a closed polygon). This keeps the ShapeDrawingWindow
                        // rendering and the node rasterization consistent.
                        var closed = false;
                        if (segment.Count >= 3)
                        {
                            var a = segment[0];
                            var last = segment[segment.Count - 1];
                            const double eps = 1e-6;
                            if (Math.Abs(a.X - last.X) < eps && Math.Abs(a.Y - last.Y) < eps)
                                closed = true;
                        }


                        sampledPaths.Add((new List<Point>(segment), closed, Math.Max(1f, segWidth), segColor));
                        segment.Clear();
                        segWidth = 1f;
                        segColor = Colors.White;
                    }
                }
                else
                {
                    segment.Add(pt);
                }
            }
            if (segment.Count > 0)
            {
                var closed = false;
                if (segment.Count >= 3)
                {
                    var a = segment[0];
                    var last = segment[segment.Count - 1];
                    const double eps = 1e-6;
                    if (Math.Abs(a.X - last.X) < eps && Math.Abs(a.Y - last.Y) < eps)
                        closed = true;
                }
                sampledPaths.Add((new List<Point>(segment), closed, Math.Max(1f, segWidth), segColor));
            }
        }

        var size = context.TileSize;
        var buffer = new PixelBuffer(size, size);
        var halfSize = size * 0.5f;
        var radius = halfSize * sizeParam * 1.4142f;
        var cosR = MathF.Cos(rotation);
        var sinR = MathF.Sin(rotation);

        // Rasterize each stroke individually to build a combined boolean mask and a
        // per-pixel color mask. Rendering each stroke separately preserves the draw
        // colors from ShapeDrawingWindow so the node output matches the preview.
        bool[,]? customMask = null;
        Color[,]? customColorMask = null;
        if (sampledPaths != null && sampledPaths.Count > 0)
        {
            customMask = new bool[size, size];
            customColorMask = new Color[size, size];
            foreach (var (sampled, closed, width, color) in sampledPaths)
            {
                bool[,] strokeMask;
                if (width < 0f) // sentinel: filled polygon
                {
                    strokeMask = PixelRaster.RasterizeFillFromNormalizedPath(size, sampled);
                }
                else
                {
                    var strokePaths = new List<(List<Point>, bool, float)> { (sampled, closed, width) };
                    strokeMask = PixelRaster.RasterizeFromNormalizedPaths(size, strokePaths);
                }
                for (var sy = 0; sy < size; sy++)
                    for (var sx = 0; sx < size; sx++)
                        if (strokeMask[sx, sy])
                        {
                            customMask[sx, sy] = true;
                            customColorMask[sx, sy] = color;
                        }
            }
        }

        // Capture class-level dither pattern locally to avoid repeated closure lookups inside the hot loop.
        var ditherPattern = s_ditherPattern;

        buffer.ParallelForEachPixel((x, y) =>
        {
            float pixR = r, pixG = g, pixB = b;
            var cx = x - halfSize + 0.5f - offsetX * size;
            var cy = y - halfSize + 0.5f - offsetY * size;

            // Apply rotation
            if (MathF.Abs(rotation) > 0.001f)
            {
                var rcx = cx * cosR + cy * sinR;
                var rcy = -cx * sinR + cy * cosR;
                cx = rcx;
                cy = rcy;
            }

            // Apply X/Y scale
            cx /= MathF.Max(0.1f, scaleX);
            cy /= MathF.Max(0.1f, scaleY);

            float distance;
            switch (shape)
            {
                case "rectangle":
                    distance = MathF.Max(MathF.Abs(cx), MathF.Abs(cy));
                    break;
                case "diamond":
                    distance = (MathF.Abs(cx) + MathF.Abs(cy)) * 0.7071f;
                    break;
                case "triangle":
                    var tx = cx / radius;
                    var ty = cy / radius;
                    var k = MathF.Sqrt(3f);
                    tx = MathF.Abs(tx) - 0.5f;
                    ty = ty + 0.5f / k;
                    if (tx + k * ty > 0f)
                    {
                        var ntx = (tx - k * ty) / 2f;
                        var nty = (-k * tx - ty) / 2f;
                        tx = ntx; ty = nty;
                    }
                    tx = Math.Clamp(tx, -1f, 0f);
                    distance = -MathF.Sqrt(tx * tx + ty * ty) * MathF.Sign(ty) * radius;
                    distance = MathF.Max(0f, -distance);
                    break;
                case "pentagon":
                    distance = RegularPolygonDistance(cx, cy, 5) * 1.05f;
                    break;
                case "hexagon":
                    distance = RegularPolygonDistance(cx, cy, 6);
                    break;
                case "star":
                    distance = StarDistance(cx, cy, radius);
                    break;
                case "cross":
                    var absCx = MathF.Abs(cx);
                    var absCy = MathF.Abs(cy);
                    var armWidth = radius * 0.35f;
                    distance = MathF.Min(
                        MathF.Max(absCx - armWidth, absCy),
                        MathF.Max(absCy - armWidth, absCx));
                    break;
                case "ring":
                    var ringDist = MathF.Sqrt(cx * cx + cy * cy);
                    distance = MathF.Abs(ringDist - radius * 0.6f);
                    distance *= 2.5f;
                    break;
                case "custom":
                    if (customMask != null)
                    {
                        // Use truncating int cast (floor for non-negative values) so pixel x maps
                        // exactly to mask index x, avoiding the banker's-rounding misalignment
                        // that MathF.Round produces for half-integer positions (x+0.5).
                        var ix = Math.Clamp((int)(cx + halfSize), 0, size - 1);
                        var iy = Math.Clamp((int)(cy + halfSize), 0, size - 1);
                        if (customMask[ix, iy])
                        {
                            distance = 0f;
                            if (customColorMask != null)
                            {
                                var pc = customColorMask[ix, iy];
                                pixR = pc.R / 255f;
                                pixG = pc.G / 255f;
                                pixB = pc.B / 255f;
                            }
                        }
                        else
                        {
                            distance = float.MaxValue;
                        }
                    }
                    else
                    {
                        distance = MathF.Sqrt(cx * cx + cy * cy);
                    }
                    break;
                default: // circle
                    distance = MathF.Sqrt(cx * cx + cy * cy);
                    break;
            }

            float alpha;
            if (hardness >= 0.99f)
            {
                alpha = distance <= radius ? 1f : 0f;
            }
            else
            {
                var feather = radius * (1f - hardness);
                alpha = 1f - SmoothStep(radius - feather, radius, distance);
            }

            if (invert) alpha = 1f - alpha;

            // Dithering — use shared precomputed pattern
            if (dither && alpha > 0.01f && alpha < 0.99f)
            {
                var threshold = ditherPattern[y % 4, x % 4];
                alpha = alpha > threshold ? 1f : 0f;
            }

            // Stroke (preserve previous semantics: stroke area is near shape boundary)
            if (strokeWidth > 0f && alpha > 0.01f)
            {
                // compute stroke extents once per pixel but avoid allocating
                var strokePixels = strokeWidth * size;
                var innerDist = radius - strokePixels;
                if (distance > innerDist && distance <= radius)
                {
                    buffer.SetPixel(x, y, strokeR, strokeG, strokeB, alpha);
                    return;
                }
            }

            buffer.SetPixel(x, y, pixR, pixG, pixB, alpha);
        });

        return buffer;


    private static readonly float[,] s_ditherPattern = { { 0f, 0.5f, 0.125f, 0.625f }, { 0.75f, 0.25f, 0.875f, 0.375f }, { 0.1875f, 0.6875f, 0.0625f, 0.5625f }, { 0.9375f, 0.4375f, 0.8125f, 0.3125f } };

private static float RegularPolygonDistance(float cx, float cy, int sides)
    {
        var angle = MathF.Atan2(cy, cx);
        var segAngle = MathF.Tau / sides;
        var halfSeg = segAngle * 0.5f;
        var localAngle = MathF.Abs(((angle % segAngle) + segAngle) % segAngle - halfSeg);
        var dist = MathF.Sqrt(cx * cx + cy * cy);
        return dist * MathF.Cos(halfSeg) / MathF.Cos(localAngle);
    }

private static float StarDistance(float cx, float cy, float radius)
    {
        const int points = 10;
        var verts = new (float x, float y)[points];
        for (int k = 0; k < points; k++)
        {
            double angle = Math.PI * k / 5.0 - Math.PI / 2.0;
            double r = k % 2 == 0 ? 1.0 : 0.38;
            verts[k] = ((float)(Math.Cos(angle) * r), (float)(Math.Sin(angle) * r));
        }

        float px = cx / radius;
        float py = cy / radius;
        float minDist = float.MaxValue;
        for (int i = 0; i < points; i++)
        {
            var (ax, ay) = verts[i];
            var (bx, by) = verts[(i + 1) % points];
            float abx = bx - ax;
            float aby = by - ay;
            float apx = px - ax;
            float apy = py - ay;
            float dot = apx * abx + apy * aby;
            float lenSq = abx * abx + aby * aby;
            float t = lenSq > 0f ? Math.Clamp(dot / lenSq, 0f, 1f) : 0f;
            float cpx = ax + t * abx;
            float cpy = ay + t * aby;
            float dx = px - cpx;
            float dy = py - cpy;
            float d = MathF.Sqrt(dx * dx + dy * dy);
            if (d < minDist) minDist = d;
        }
        return minDist * radius;
    }
}
